from flask import Flask, request, jsonify
import cv2
import numpy as np

# Load the model
face_cascade = cv2.CascadeClassifier('haarcascade_frontalface_default.xml')

app = Flask(__name__)

@app.route('/api/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({"error": "No image provided."}), 400
    
    file = request.files['image']
    npimg = np.fromfile(file, dtype=np.uint8)
    img = cv2.imdecode(npimg, -1)

    # Detect faces in the image
    gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
    faces = face_cascade.detectMultiScale(gray, scaleFactor=1.3, minNeighbors=5)
    
    if len(faces) == 0:
        return jsonify({"error": "No face detected in the image."}), 400

    # For each face found, draw a rectangle and identify the face
    for (x, y, w, h) in faces:
        cv2.rectangle(img, (x, y), (x+w, y+h), (255, 0, 0), 2)
        
    # After drawing rectangles around the faces and detecting them, return the resultant image
    retval, img_encoded = cv2.imencode('.jpg', img)
    response = img_encoded.tobytes()
    
    return jsonify({"image": str(response), "detected": len(faces)}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)